const b = $input.item.json.body || $input.item.json;
const appointment_id   = b.appointment_id   || null;
const client_id        = b.client_id        || null;
const client_email     = b.client_email     || '';
const client_name      = b.client_name      || 'Cliente';
const client_phone     = b.client_phone     || '';
const appointment_type = b.appointment_type || 'consulenza';
const scheduled_at     = b.scheduled_at     || null;
const notes            = b.notes            || '';
const location         = b.location         || 'integrations:whatsapp_video';
if (!scheduled_at) throw new Error('scheduled_at mancante');
const eventTypeMap = { 'consulenza': 5147645, 'pre-seduta': 5147653, 'seduta': 5147823 };
const eventTypeId  = eventTypeMap[appointment_type] || 5147645;
const startDate    = new Date(scheduled_at);
const endIso       = new Date(startDate.getTime() + 60 * 60 * 1000).toISOString();
const typeLabel    = { 'consulenza':'Consulenza','pre-seduta':'Pre-Seduta','seduta':'Seduta' }[appointment_type] || appointment_type;
const dateFormatted = startDate.toLocaleDateString('it-IT', { weekday:'long', day:'2-digit', month:'long', year:'numeric' });
const timeFormatted = startDate.toLocaleTimeString('it-IT', { hour:'2-digit', minute:'2-digit', timeZone:'Europe/Rome' });
const attendee = { name: client_name, email: client_email, timeZone: 'Europe/Rome', language: 'it' };
if (client_phone) attendee.phoneNumber = client_phone;
const calBody = { eventTypeId, start: scheduled_at, attendee, metadata: {} };
if (notes) calBody.bookingFieldsResponses = { notes };
const calBodyString = JSON.stringify(calBody);
return [{ json: { appointment_id, client_id, client_email, client_name, client_phone, appointment_type, typeLabel, scheduled_at, endIso, notes, eventTypeId, dateFormatted, timeFormatted, calBodyString } }];

const prev = $('Estrai Dati').item.json;
let sessionOrdinal = '1ª';
if (prev.appointment_type === 'seduta') {
  try {
    const raw = $input.item.json;
    const list = Array.isArray(raw) ? raw : [];
    if (list.length > 0) {
      const sorted = [...list].sort((a,b) => new Date(a.scheduled_at)-new Date(b.scheduled_at));
      const idx = sorted.findIndex(a => a.id === prev.appointment_id);
      const n = idx >= 0 ? idx + 1 : list.length;
      const ord = ['1ª','2ª','3ª','4ª','5ª','6ª','7ª','8ª','9ª','10ª'];
      sessionOrdinal = ord[n-1] || `${n}ª`;
    }
  } catch(e) { sessionOrdinal = '1ª'; }
}
return [{ json: { ...prev, sessionOrdinal } }];

const cal = $input.item.json;
const uid = cal?.data?.uid || cal?.uid || null;
return [{ json: { ...($('Calcola Ordinal').item.json), cal_booking_uid: uid } }];
